package api

import "testing"

func TestDecodePolymarketMatchOrdersInputExtractsTargetOrderFields(t *testing.T) {
	input := ""
	orders, err := DecodePolymarketMatchOrdersInput(input)
	if err != nil {
		t.Fatalf("DecodePolymarketMatchOrdersInput failed: %v", err)
	}
	if len(orders) != 3 {
		t.Fatalf("expected 3 decoded orders, got %d", len(orders))
	}
	target := orders[1]
	if target.Maker != "0x89b5cdaaa4866c1e738406712012a630b4078beb" {
		t.Fatalf("unexpected maker %s", target.Maker)
	}
	if target.TokenID != "110495547850784090351934591125943750192177919830663671135183870912697271206961" {
		t.Fatalf("unexpected token id %s", target.TokenID)
	}
	if target.sideString() != "BUY" {
		t.Fatalf("unexpected side %s", target.sideString())
	}
	if got := target.fillSize(); got < 15.89 || got > 15.91 {
		t.Fatalf("unexpected share size %.6f", got)
	}
}

func TestMarketFromGammaEventTokenIDFindsOutcome(t *testing.T) {
	event := &GammaEvent{
		Slug: "eth-updown-5m-1774878600",
		Markets: []GammaMarket{
			{
				ConditionID:  "cond-1",
				ClobTokenIds: "[\"token-up\",\"token-down\"]",
				Outcomes:     "[\"Up\",\"Down\"]",
				Active:       true,
			},
		},
	}
	market, outcome, ok := marketFromGammaEventTokenID(event, "token-down")
	if !ok {
		t.Fatal("expected token to resolve")
	}
	if market.Slug != "eth-updown-5m-1774878600" {
		t.Fatalf("unexpected slug %s", market.Slug)
	}
	if outcome != "Down" {
		t.Fatalf("unexpected outcome %s", outcome)
	}
}

func TestResolvePolymarketPendingWSURL(t *testing.T) {
	t.Run("prefers explicit websocket url", func(t *testing.T) {
		got := ResolvePolymarketPendingWSURL(
			"wss://polygon-mainnet.g.alchemy.com/v2/explicit",
			"https://polygon-mainnet.g.alchemy.com/v2/fallback",
		)
		want := "wss://polygon-mainnet.g.alchemy.com/v2/explicit"
		if got != want {
			t.Fatalf("unexpected resolved url %q want %q", got, want)
		}
	})

	t.Run("normalizes explicit https alchemy url", func(t *testing.T) {
		got := ResolvePolymarketPendingWSURL(
			"https://polygon-mainnet.g.alchemy.com/v2/explicit",
			"",
		)
		want := "wss://polygon-mainnet.g.alchemy.com/v2/explicit"
		if got != want {
			t.Fatalf("unexpected resolved url %q want %q", got, want)
		}
	})

	t.Run("falls back to polygon rpc url", func(t *testing.T) {
		got := ResolvePolymarketPendingWSURL(
			"",
			"https://polygon-mainnet.g.alchemy.com/v2/fallback",
		)
		want := "wss://polygon-mainnet.g.alchemy.com/v2/fallback"
		if got != want {
			t.Fatalf("unexpected resolved url %q want %q", got, want)
		}
	})

	t.Run("ignores non alchemy polygon rpc url", func(t *testing.T) {
		got := ResolvePolymarketPendingWSURL(
			"",
			"https://polygon-rpc.com",
		)
		if got != "" {
			t.Fatalf("expected empty resolved url, got %q", got)
		}
	})
}
